package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringWriter;
import java.lang.reflect.Field;
import java.lang.reflect.Method;
import java.lang.reflect.Proxy;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.stubbing.Answer;

class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testFormatWithNormalValues() {
        String result = csvFormat.format("a", "b", "c");
        assertEquals("a,b,c", result);
    }

    @Test
    void testFormatWithNullValue() {
        CSVFormat format = CSVFormat.DEFAULT.withNullString("NULL");
        String result = format.format("a", null, "c");
        assertEquals("a,NULL,c", result);
    }

    @Test
    void testFormatWithEmptyValues() {
        String result = csvFormat.format();
        assertEquals("", result);
    }

    @Test
    void testFormatWithValuesContainingComma() {
        String result = csvFormat.format("a,b", "c");
        assertEquals("\"a,b\",c", result);
    }

    @Test
    void testFormatThrowsIllegalStateExceptionOnIOException() throws Exception {
        // Create a spy of CSVFormat.DEFAULT
        CSVFormat format = spy(CSVFormat.DEFAULT);

        // Mock CSVPrinter that throws IOException on printRecord
        CSVPrinter mockPrinter = mock(CSVPrinter.class);
        doThrow(new IOException("IO error")).when(mockPrinter).printRecord((Object[]) any());

        // Use reflection to replace the private method 'format' to use our mockPrinter
        // CSVFormat.format(Object...) is final, so we cannot mock it directly.
        // Instead, we create a proxy CSVFormat that overrides format method via reflection.

        // Create a dynamic proxy for CSVFormat that overrides the format method
        CSVFormat proxyFormat = (CSVFormat) Proxy.newProxyInstance(
                CSVFormat.class.getClassLoader(),
                new Class[]{CSVFormat.class},
                (proxy, method, args) -> {
                    if ("format".equals(method.getName()) && args.length == 1 && args[0] instanceof Object[]) {
                        Object[] values = (Object[]) args[0];
                        StringWriter out = new StringWriter();
                        try (CSVPrinter printer = mockPrinter) {
                            printer.printRecord(values);
                        } catch (IOException e) {
                            throw new IllegalStateException(e);
                        }
                        return out.toString().trim();
                    }
                    return method.invoke(format, args);
                });

        IllegalStateException exception = assertThrows(IllegalStateException.class, () -> {
            proxyFormat.format("a", "b");
        });
        assertTrue(exception.getCause() instanceof IOException);
        assertEquals("IO error", exception.getCause().getMessage());
    }

}
